interface LanguageContextType {
  language: Language
  setLanguage: (lang: Language) => void
  t: (key: string, replacements?: Record<string, string | number>) => string
  supportedLanguages: typeof supportedLanguages
}

const LanguageContext = createContext<LanguageContextType | undefined>(undefined)

export function LanguageProvider({ children }: { children: ReactNode }) {
  const [language, setLanguage] = useState<Language>("es")

  useEffect(() => {
    const storedLanguage = window.localStorage.getItem("site-language") as Language | null
    if (storedLanguage && supportedLanguages.some((lang) => lang.code === storedLanguage)) {
      setLanguage(storedLanguage)
      return
    }

    const browserLang = navigator.language.split("-")[0] as Language
    if (supportedLanguages.some((lang) => lang.code === browserLang)) {
      setLanguage(browserLang)
    }
  }, [])

  useEffect(() => {
    window.localStorage.setItem("site-language", language)
  }, [language])

  const t = (key: string, replacements?: Record<string, string | number>): string => {
    const translation = translations[key]?.[language] ?? translations[key]?.["en"] ?? key
    if (!replacements) {
      return translation
    }

    return Object.entries(replacements).reduce((current, [placeholder, value]) => {
      return current.replace(new RegExp(`\\{\\{?${placeholder}\\}?\\}`, "g"), String(value))
    }, translation)
  }

  return (
    <LanguageContext.Provider value={{ language, setLanguage, t, supportedLanguages }}>
      {children}
    </LanguageContext.Provider>
  )
}

export function useLanguage() {
  const context = useContext(LanguageContext)
  if (!context) {
    throw new Error("useLanguage must be used within a LanguageProvider")
  }
  return context
}


